"""Query engines for different galaxy catalogs."""

from abc import ABC, abstractmethod

import numpy as np
import pandas as pd
from astropy import units as u
from astropy.coordinates import SkyCoord
from astroquery.ipac.ned import Ned
from astroquery.vizier import Vizier

from .config import COSMO


class BaseEngine(ABC):
    """Abstract base class for catalog query engines."""

    @abstractmethod
    def query(self, coord: SkyCoord, radius: u.Quantity) -> pd.DataFrame:
        pass


class NedEngine(BaseEngine):
    """Engine for querying NASA/IPAC Extragalactic Database (NED)."""

    def __init__(self):
        Ned.TIMEOUT = 180

    def query(self, coord: SkyCoord, radius: u.Quantity) -> pd.DataFrame:
        try:
            result_table = Ned.query_region(coord, radius=radius)
            if result_table is None or len(result_table) == 0:
                return pd.DataFrame()

            df = result_table.to_pandas()
            # Standardize columns. Keep NED's object Type (e.g. 'GClstr', 'GGroup')
            # as 'classification' so the search can apply the cluster impact threshold.
            df = df.rename(
                columns={
                    "Object Name": "name",
                    "RA": "ra",
                    "DEC": "dec",
                    "Redshift": "z",
                    "Type": "classification",
                }
            )
            df["catalog"] = "NED"
            keep = ["name", "ra", "dec", "z", "catalog"]
            if "classification" in df.columns:
                keep.insert(4, "classification")
            return df[keep]
        except Exception as e:
            print(f"NED query failed: {e}")
            return pd.DataFrame()


class VizierEngine(BaseEngine):
    """Engine for querying Vizier catalogs (GLADE+, DESI, etc.)."""

    def __init__(self, catalog_id: str):
        self.catalog_id = catalog_id
        self.vizier = Vizier(row_limit=-1)

    def query(self, coord: SkyCoord, radius: u.Quantity) -> pd.DataFrame:
        try:
            result = self.vizier.query_region(coord, radius=radius, catalog=self.catalog_id)
            if not result:
                return pd.DataFrame()

            df = result[0].to_pandas()
            if df.empty:
                return df

            # print(f"DEBUG: Vizier {self.catalog_id} columns: {df.columns.tolist()}")

            # Standardize common Vizier column names
            rename_map = {
                "RAJ2000": "ra",
                "DEJ2000": "dec",
                "z": "z",
                "zphot": "z",  # DESI DR8 North
                "z_best": "z",  # GLADE+ best redshift
                "z_helio": "z",  # GLADE+ heliocentric redshift
                "z_phot": "z",
                "zph": "z",
                "z_cmb": "z",
                "zph2MPZ": "z",
            }
            # Case-insensitive mapping
            current_cols = {c.lower(): c for c in df.columns}
            final_rename = {}
            for target_low, target_std in rename_map.items():
                if target_low.lower() in current_cols:
                    final_rename[current_cols[target_low.lower()]] = target_std

            df = df.rename(columns=final_rename)
            df["catalog"] = self.catalog_id
            df = _add_desi_stellar_mass(df, self.catalog_id)
            return df
        except Exception as e:
            print(f"Vizier query ({self.catalog_id}) failed: {e}")
            return pd.DataFrame()


PS1_CATALOG = "II/349/ps1"
PS1_MATCH_RADIUS = 3.0 * u.arcsec


def query_ps1_gi_mags(coord: SkyCoord, match_radius: u.Quantity = PS1_MATCH_RADIUS):
    """Nearest Pan-STARRS1 (II/349/ps1) source to ``coord`` within ``match_radius``.

    Returns ``(g_mag, i_mag, sep_arcsec)``. Kron magnitudes are preferred over
    mean-PSF mags: Taylor+2011 (the g-i/M_i estimator these feed) was calibrated
    on Kron-like GAMA total magnitudes, and Kron better captures extended-source
    flux. PS1 AB mags are used directly; the small PS1->SDSS color terms are
    neglected at the order-of-magnitude precision of these halo-mass estimates.

    The DESI VII/292 photo-z catalog carries no photometry, so this PS1 match is
    the only route to a measured stellar mass for DESI-only sightlines. Faint,
    high-z galaxies fall below the shallow PS1 3pi depth and simply will not
    match; callers then fall back to an assumed mass. Either of ``g_mag`` /
    ``i_mag`` may be ``None`` if not finite, and the result is
    ``(None, None, None)`` on no match or query failure.
    """
    try:
        v = Vizier(columns=["RAJ2000", "DEJ2000", "gmag", "imag", "gKmag", "iKmag"], row_limit=50)
        res = v.query_region(coord, radius=match_radius, catalog=PS1_CATALOG)
    except Exception as e:
        print(f"PS1 query failed: {e}")
        return None, None, None

    if not res or len(res[0]) == 0:
        return None, None, None

    t = res[0]
    matches = SkyCoord(t["RAJ2000"], t["DEJ2000"], unit="deg")
    seps = coord.separation(matches).arcsec
    j = int(np.argmin(seps))

    def _pick(kron_col: str, psf_col: str):
        for col in (kron_col, psf_col):
            if col in t.colnames:
                val = t[col][j]
                if val is not None and np.isfinite(val):
                    return float(val)
        return None

    return _pick("gKmag", "gmag"), _pick("iKmag", "imag"), float(seps[j])


def _is_desi_dr8_north(catalog_id: str) -> bool:
    return catalog_id.lower() == "vii/292/north"


def _is_glade_plus(catalog_id: str) -> bool:
    return catalog_id.lower() == "vii/291/glade"


def _find_column(df: pd.DataFrame, candidates: tuple[str, ...]) -> str | None:
    columns = {column.lower(): column for column in df.columns}
    for candidate in candidates:
        if candidate.lower() in columns:
            return columns[candidate.lower()]
    return None


def _standardize_mass_column(df: pd.DataFrame) -> pd.DataFrame:
    mass_col = _find_column(df, ("M_star", "Mstar", "logMstar", "logM_star", "logMass", "logM"))
    if mass_col is not None and mass_col != "M_star":
        df = df.rename(columns={mass_col: "M_star"})
    return df


def _add_desi_stellar_mass(df: pd.DataFrame, catalog_id: str) -> pd.DataFrame:
    df = _standardize_mass_column(df)

    if _is_glade_plus(catalog_id):
        if "M_star" in df.columns:
            df["mass_source"] = "catalog"
        return df

    if not _is_desi_dr8_north(catalog_id):
        return df

    g_col = _find_column(df, ("flux_g", "fluxg", "gflux", "g_flux", "flx_g"))
    r_col = _find_column(df, ("flux_r", "fluxr", "rflux", "r_flux", "flx_r"))
    z_col = _find_column(df, ("flux_z", "fluxz", "zflux", "z_flux", "flx_z"))
    if g_col is None or r_col is None or z_col is None or "z" not in df.columns:
        return df

    g_flux = pd.to_numeric(df[g_col], errors="coerce")
    r_flux = pd.to_numeric(df[r_col], errors="coerce")
    z_flux = pd.to_numeric(df[z_col], errors="coerce")
    redshift = pd.to_numeric(df["z"], errors="coerce")
    valid = (g_flux > 0.0) & (r_flux > 0.0) & (z_flux > 0.0) & (redshift > 0.0)
    if not valid.any():
        return df

    g_mag = 22.5 - 2.5 * np.log10(g_flux[valid])
    r_mag = 22.5 - 2.5 * np.log10(r_flux[valid])
    d_l_pc = COSMO.luminosity_distance(redshift[valid].to_numpy()).to(u.pc).value
    distance_modulus = 5.0 * np.log10(d_l_pc / 10.0)
    absolute_r = r_mag - distance_modulus
    log_mass = -0.68 + 0.70 * (g_mag - r_mag) - 0.4 * absolute_r

    df.loc[valid, "M_star"] = log_mass
    df.loc[valid, "mass_source"] = "photometric"
    return df

"""Additional opt-in catalog engines for galaxy searches."""

import numpy as np
import pandas as pd
import pyvo
from astropy import units as u
from astropy.coordinates import SkyCoord

from .engines import BaseEngine, VizierEngine


NOIRLAB_TAP_URL = "https://datalab.noirlab.edu/tap"


def _mask_sentinels(df: pd.DataFrame) -> pd.DataFrame:
    """Convert survey sentinel values to NaN without changing nonnumeric fields."""
    if df.empty:
        return df
    return df.replace(-9999, np.nan)


def _tap_search_to_dataframe(tap_url: str, adql: str) -> pd.DataFrame:
    svc = pyvo.dal.TAPService(tap_url)
    table = svc.search(adql).to_table()
    return _mask_sentinels(table.to_pandas())


def _ensure_standard_columns(df: pd.DataFrame, catalog: str) -> pd.DataFrame:
    df = df.copy()
    for column in ["ra", "dec", "z"]:
        if column not in df.columns:
            df[column] = np.nan
    df["catalog"] = catalog
    return df


def _tap_box_query(
    tap_url,
    table,
    coord,
    radius,
    columns,
    where=None,
    ra_col="ra",
    dec_col="dec",
) -> pd.DataFrame:
    """Query Data Lab TAP with a box prefilter, then enforce a true sky circle.

    NOIRLab Astro Data Lab rejects ADQL geometry functions for these tables
    ("function point does not exist"), so use a portable RA/Dec BETWEEN box and
    perform the physically correct circular cut with Astropy on the client side.
    """
    try:
        radius_deg = radius.to(u.deg).value
        ra0 = coord.ra.deg
        dec0 = coord.dec.deg
        ddec = radius_deg
        cos_dec = max(abs(np.cos(np.radians(dec0))), 1.0e-6)
        dra = radius_deg / cos_dec

        predicates = [
            f"{dec_col} BETWEEN {dec0 - ddec:.12g} AND {dec0 + ddec:.12g}",
            f"{ra_col} BETWEEN {ra0 - dra:.12g} AND {ra0 + dra:.12g}",
        ]
        if where is not None:
            predicates.append(f"({where})")

        adql = (
            f"SELECT {', '.join(columns)} "
            f"FROM {table} "
            f"WHERE {' AND '.join(predicates)}"
        )
        df = _tap_search_to_dataframe(tap_url, adql)
        if df.empty:
            return pd.DataFrame()

        matches = SkyCoord(df[ra_col].to_numpy() * u.deg, df[dec_col].to_numpy() * u.deg)
        df = df.loc[coord.separation(matches) <= radius].copy()
        if df.empty:
            return pd.DataFrame()
        return df.rename(columns={ra_col: "ra", dec_col: "dec"})
    except Exception:
        return pd.DataFrame()


class DesiDr1Engine(BaseEngine):
    def __init__(self, tap_url=NOIRLAB_TAP_URL, require_primary=True):
        self.tap_url = tap_url
        self.require_primary = require_primary

    def query(self, coord, radius) -> pd.DataFrame:
        columns = [
            "mean_fiber_ra",
            "mean_fiber_dec",
            "z",
            "zerr",
            "zwarn",
            "spectype",
            "deltachi2",
            "targetid",
            "zcat_primary",
        ]
        where = "zcat_primary='true' AND zwarn=0" if self.require_primary else "zwarn=0"
        df = _tap_box_query(
            self.tap_url,
            "desi_dr1.zpix",
            coord,
            radius,
            columns,
            where=where,
            ra_col="mean_fiber_ra",
            dec_col="mean_fiber_dec",
        )
        if df.empty:
            return pd.DataFrame()

        return _ensure_standard_columns(df, "DESI_DR1")

    def query_emfit(self, targetids) -> pd.DataFrame:
        return self._query_targetid_table("desi_dr1.emfit", targetids)

    def query_agngal(self, targetids) -> pd.DataFrame:
        return self._query_targetid_table("desi_dr1.agngal", targetids)

    def _query_targetid_table(self, table, targetids) -> pd.DataFrame:
        ids = [int(targetid) for targetid in targetids]
        if not ids:
            return pd.DataFrame()

        try:
            adql = f"SELECT * FROM {table} WHERE targetid IN ({', '.join(map(str, ids))})"
            return _tap_search_to_dataframe(self.tap_url, adql)
        except Exception:
            return pd.DataFrame()


class DesiLsDr10Engine(BaseEngine):
    def __init__(self, tap_url=NOIRLAB_TAP_URL):
        self.tap_url = tap_url

    def query(self, coord, radius) -> pd.DataFrame:
        # At Dec +70..+74, Legacy Survey DR10 i-band fields are -9999 sentinels;
        # selecting only grz/Wise avoids surfacing nonphysical placeholder data.
        columns = [
            "ra",
            "dec",
            "type",
            "flux_g",
            "flux_r",
            "flux_z",
            "flux_w1",
            "flux_w2",
            "flux_w3",
            "flux_w4",
            "dered_flux_g",
            "dered_flux_r",
            "dered_flux_z",
            "shape_e1",
            "shape_e2",
            "shape_r",
            "sersic",
            "ref_cat",
        ]
        df = _tap_box_query(self.tap_url, "ls_dr10.tractor", coord, radius, columns)
        if df.empty:
            return pd.DataFrame()

        # Data Lab's ls_dr10.photo_z table is empty at these DSA-110 declinations.
        df = df.copy()
        df["z"] = np.nan
        return _ensure_standard_columns(df, "DESI_LS_DR10")


class AllWiseEngine(BaseEngine):
    def __init__(self):
        self._vizier_engine = VizierEngine("II/328/allwise")

    def query(self, coord, radius) -> pd.DataFrame:
        df = self._vizier_engine.query(coord, radius)
        if df.empty:
            return pd.DataFrame()

        return _ensure_standard_columns(df, "ALLWISE")


class GalexAisEngine(BaseEngine):
    def __init__(self):
        self._vizier_engine = VizierEngine("II/335/galex_ais")

    def query(self, coord, radius) -> pd.DataFrame:
        df = self._vizier_engine.query(coord, radius)
        if df.empty:
            return pd.DataFrame()

        df = df.copy()
        df = df.rename(columns={col: "ebv" for col in ["E(B-V)"] if col in df.columns})
        return _ensure_standard_columns(df, "GALEX_AIS")


class XscEngine(BaseEngine):
    def __init__(self):
        self._vizier_engine = VizierEngine("VII/233/xsc")

    def query(self, coord, radius) -> pd.DataFrame:
        df = self._vizier_engine.query(coord, radius)
        if df.empty:
            return pd.DataFrame()

        df = df.copy()
        df = df.rename(
            columns={
                col: new_col
                for col, new_col in {
                    "K.K20e": "Kmag",
                    "Kb/a": "axis_ratio",
                    "Kpa": "pa_deg",
                }.items()
                if col in df.columns
            }
        )
        return _ensure_standard_columns(df, "2MASS_XSC")

