from astroquery.vizier import Vizier
import warnings; warnings.simplefilter('ignore')
seen = {}
for q in ['MCXC', 'meta-catalogue X-ray clusters', 'X-ray cluster catalogue M500 R500']:
    try:
        cats = Vizier.find_catalogs(q, max_catalogs=30)
        for k, v in cats.items():
            d = v.description or ''
